module binary_adder_4bit(
    input [3:0] a,
    input [3:0] b,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

assign {carry_out, sum} = a + b + carry_in;

  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~b[1];
      carry_out <= a[2] & b[2];
    end
  end

endmodule
